import{_ as n,c as a,ap as o,o as l}from"./chunks/framework.CCxIPCIe.js";const _=JSON.parse('{"title":"rwkv7 训练踩坑","description":"","frontmatter":{"title":"rwkv7 训练踩坑","date":"2026-04-06T07:23:17.723Z","length":"982字","time":"4分钟","aside":true,"hash":972661010},"headers":[],"relativePath":"note/编程/rwkv7训练踩坑.md","filePath":"note/编程/rwkv7训练踩坑.md"}'),p={name:"note/编程/rwkv7训练踩坑.md"};function e(t,s,c,r,i,y){return l(),a("div",null,s[0]||(s[0]=[o(`<p>最近放假，正好尝试一下训练一个小语言模型。23 年的时候就耳闻 RWKV4，但囿于其生态、源码混乱以及自己码力不足等等问题一直未尝试，今天来尝试从头预训练一个 RWKV7。</p><p>RWKV7 在 github 上有两个仓库提供预训练代码：一个是 Bo 的原仓库 <a href="https://github.com/BlinkDL/RWKV-LM" target="_blank" rel="noreferrer">BlinkDL/RWKV-LM</a>，另一个是社区仓库 <a href="https://github.com/RWKV-Vibe/RWKV-LM-V7" target="_blank" rel="noreferrer">RWKV-Vibe/RWKV-LM-V7</a>，起先我拉取的是后者，因为看似后者的代码更新一些。</p><p>结果不出所料跑不起来，我只能换成 Bo 的代码，以便直接在 discord 上请教之。仍然跑不起来。下面是 debug 的记录：</p><ol><li>直接采用原代码默认的 <code>deepspeed_stage_2</code> 策略，训练框架在通过 <code>deepspeed</code> 初始化 <code>TorchBackend</code> 时就出现 SegFault，考虑在训练代码前添加</li></ol><div class="language-py"><button title="Copy Code" class="copy"></button><span class="lang">py</span><pre class="shiki solarized-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#859900;">import</span><span style="color:#839496;"> faulthandler</span></span>
<span class="line"><span style="color:#839496;">faulthandler.enable()</span></span></code></pre></div><p>打印 SegFault 前的最后的调用栈。发现是 <code>torch.broadcast</code> 的问题。于是考虑运行下面的测试脚本：</p><div class="language-py"><button title="Copy Code" class="copy"></button><span class="lang">py</span><pre class="shiki solarized-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#859900;">import</span><span style="color:#839496;"> torch</span></span>
<span class="line"><span style="color:#859900;">import</span><span style="color:#839496;"> torch.distributed </span><span style="color:#859900;">as</span><span style="color:#839496;"> dist</span></span>
<span class="line"><span style="color:#859900;">import</span><span style="color:#839496;"> os</span></span>
<span class="line"></span>
<span class="line"><span style="color:#839496;">os.environ[</span><span style="color:#2AA198;">&#39;NCCL_IB_DISABLE&#39;</span><span style="color:#839496;">] </span><span style="color:#859900;">=</span><span style="color:#2AA198;"> &#39;1&#39;</span></span>
<span class="line"><span style="color:#586E75;font-style:italic;">    # 模拟 Lightning 的 DDP/DeepSpeed 初始化环境</span></span>
<span class="line"><span style="color:#839496;">os.environ[</span><span style="color:#2AA198;">&#39;MASTER_ADDR&#39;</span><span style="color:#839496;">] </span><span style="color:#859900;">=</span><span style="color:#2AA198;"> &#39;localhost&#39;</span></span>
<span class="line"><span style="color:#839496;">os.environ[</span><span style="color:#2AA198;">&#39;MASTER_PORT&#39;</span><span style="color:#839496;">] </span><span style="color:#859900;">=</span><span style="color:#2AA198;"> &#39;12355&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#93A1A1;font-weight:bold;">def</span><span style="color:#268BD2;"> test_broadcast</span><span style="color:#839496;">():</span></span>
<span class="line"><span style="color:#586E75;font-style:italic;">    # 这里的 backend 换成 &quot;nccl&quot; (GPU) 或 &quot;gloo&quot; (CPU)</span></span>
<span class="line"><span style="color:#586E75;font-style:italic;">    # 如果 nccl 崩了，试试 gloo</span></span>
<span class="line"><span style="color:#839496;">    dist.init_process_group(backend</span><span style="color:#859900;">=</span><span style="color:#2AA198;">&quot;nccl&quot;</span><span style="color:#839496;">, rank</span><span style="color:#859900;">=</span><span style="color:#D33682;">0</span><span style="color:#839496;">, world_size</span><span style="color:#859900;">=</span><span style="color:#D33682;">1</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#839496;">    </span></span>
<span class="line"><span style="color:#586E75;font-style:italic;">    # 模拟 Lightning 的 log_dir 字符串广播</span></span>
<span class="line"><span style="color:#839496;">    test_path </span><span style="color:#859900;">=</span><span style="color:#2AA198;"> &quot;/home/ids/smao-22/phd/chongmo/out/test_dir&quot;</span></span>
<span class="line"><span style="color:#839496;">    object_list </span><span style="color:#859900;">=</span><span style="color:#839496;"> [test_path]</span></span>
<span class="line"><span style="color:#839496;">    </span></span>
<span class="line"><span style="color:#268BD2;">    print</span><span style="color:#839496;">(</span><span style="color:#93A1A1;font-weight:bold;">f</span><span style="color:#2AA198;">&quot;Before broadcast: </span><span style="color:#CB4B16;">{</span><span style="color:#839496;">object_list</span><span style="color:#CB4B16;">}</span><span style="color:#2AA198;">&quot;</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#859900;">    try</span><span style="color:#839496;">:</span></span>
<span class="line"><span style="color:#586E75;font-style:italic;">        # Lightning 内部实际调用的就是这个</span></span>
<span class="line"><span style="color:#839496;">        dist.broadcast_object_list(object_list, src</span><span style="color:#859900;">=</span><span style="color:#D33682;">0</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#268BD2;">        print</span><span style="color:#839496;">(</span><span style="color:#93A1A1;font-weight:bold;">f</span><span style="color:#2AA198;">&quot;After broadcast: </span><span style="color:#CB4B16;">{</span><span style="color:#839496;">object_list</span><span style="color:#CB4B16;">}</span><span style="color:#2AA198;">&quot;</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#859900;">    except</span><span style="color:#CB4B16;"> Exception</span><span style="color:#859900;"> as</span><span style="color:#839496;"> e:</span></span>
<span class="line"><span style="color:#268BD2;">        print</span><span style="color:#839496;">(</span><span style="color:#93A1A1;font-weight:bold;">f</span><span style="color:#2AA198;">&quot;Broadcast failed with error: </span><span style="color:#CB4B16;">{</span><span style="color:#839496;">e</span><span style="color:#CB4B16;">}</span><span style="color:#2AA198;">&quot;</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#839496;">    </span></span>
<span class="line"><span style="color:#839496;">    dist.destroy_process_group()</span></span>
<span class="line"></span>
<span class="line"><span style="color:#93A1A1;font-weight:bold;">def</span><span style="color:#268BD2;"> test_tensor_broadcast</span><span style="color:#839496;">():</span></span>
<span class="line"><span style="color:#839496;">    dist.init_process_group(backend</span><span style="color:#859900;">=</span><span style="color:#2AA198;">&quot;nccl&quot;</span><span style="color:#839496;">, rank</span><span style="color:#859900;">=</span><span style="color:#D33682;">0</span><span style="color:#839496;">, world_size</span><span style="color:#859900;">=</span><span style="color:#D33682;">1</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#839496;">    </span></span>
<span class="line"><span style="color:#586E75;font-style:italic;">    # 创建一个简单的 Tensor，不涉及 Python 对象序列化</span></span>
<span class="line"><span style="color:#839496;">    x </span><span style="color:#859900;">=</span><span style="color:#839496;"> torch.ones(</span><span style="color:#D33682;">10</span><span style="color:#839496;">).cuda()</span></span>
<span class="line"><span style="color:#268BD2;">    print</span><span style="color:#839496;">(</span><span style="color:#2AA198;">&quot;Tensor before broadcast:&quot;</span><span style="color:#839496;">, x)</span></span>
<span class="line"><span style="color:#839496;">    </span></span>
<span class="line"><span style="color:#859900;">    try</span><span style="color:#839496;">:</span></span>
<span class="line"><span style="color:#586E75;font-style:italic;">        # 直接广播原始内存数据</span></span>
<span class="line"><span style="color:#839496;">        dist.broadcast(x, src</span><span style="color:#859900;">=</span><span style="color:#D33682;">0</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#268BD2;">        print</span><span style="color:#839496;">(</span><span style="color:#2AA198;">&quot;Tensor broadcast success!&quot;</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#859900;">    except</span><span style="color:#CB4B16;"> Exception</span><span style="color:#859900;"> as</span><span style="color:#839496;"> e:</span></span>
<span class="line"><span style="color:#268BD2;">        print</span><span style="color:#839496;">(</span><span style="color:#93A1A1;font-weight:bold;">f</span><span style="color:#2AA198;">&quot;Tensor broadcast failed: </span><span style="color:#CB4B16;">{</span><span style="color:#839496;">e</span><span style="color:#CB4B16;">}</span><span style="color:#2AA198;">&quot;</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#839496;">    </span></span>
<span class="line"><span style="color:#839496;">    dist.destroy_process_group()</span></span>
<span class="line"></span>
<span class="line"><span style="color:#859900;">if</span><span style="color:#839496;"> __name__ </span><span style="color:#859900;">==</span><span style="color:#2AA198;"> &quot;__main__&quot;</span><span style="color:#839496;">:</span></span>
<span class="line"><span style="color:#839496;">    test_tensor_broadcast()</span></span>
<span class="line"><span style="color:#839496;">    test_broadcast()</span></span></code></pre></div><p>报错，确认是 broadcast 问题。尝试禁用<code>os.environ[&#39;NCCL_IB_DISABLE&#39;] = &#39;1&#39;</code>以后，可以运行。IB 通信对多机分布式训练有影响，但对单机分布式依靠 NVLink，所以关闭以后问题不大。</p><ol start="2"><li>在 debug 上述问题时，我首先怀疑是分布式训练问题，于是把<code>ligthning</code>的策略从<code>deepspeed_stage_2</code>改成了<code>auto</code>，结果报<code>AssertionError</code>，发现原来 RWKV7 的前后向过程都默认采用 bf16 精度，而在其自定义的 cuda 算子中还开启了精度检查。最终确定是<code>lightning</code>的<code>auto</code>策略会在<code>precision=&#39;bf16&#39;</code>时自动开启混合精度训练，即自动在前向过程中开启<code>torch.autocast</code>。为此我在其<code>training_step</code>添加了关闭混合精度训练的装饰器：</li></ol><div class="language-py"><button title="Copy Code" class="copy"></button><span class="lang">py</span><pre class="shiki solarized-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#268BD2;">@torch.autocast</span><span style="color:#839496;">(</span><span style="color:#2AA198;">&#39;cuda&#39;</span><span style="color:#839496;">,enabled</span><span style="color:#859900;">=</span><span style="color:#B58900;">False</span><span style="color:#839496;">)</span></span>
<span class="line"><span style="color:#93A1A1;font-weight:bold;">def</span><span style="color:#268BD2;"> training_step</span><span style="color:#839496;">(self, batch, batch_idx):</span></span>
<span class="line"><span style="color:#CB4B16;">    ...</span></span></code></pre></div><p>但在开启 deepspeed 策略以后可以注释掉装饰器，因为 deepspeed 将接管精度控制。</p><p>此后便可正常训练了，以下是一些数据：</p><ul><li>[x] 单机单卡训练，单机单卡下原训练脚本有个 bug，即把 strategy 改成 auto 以后会自动在 forward pass autocast 到 float32，导致<code>RWKV7_CLAMPW_CUDA_OP</code>内部 assertion error，需在 training_step 外加装饰器\` <ul><li>设备：A40 46GiB： <ul><li>bs=8,ctx_len=4096，GRAD_CP=0，显存占用约 32GiB，1h/epoch，需要 294epochs 才能跑完一遍数据集。</li><li>bs=64,ctx_len=4096，GRAD_CP=1，显存占用约 32GiB，1h/epoch，需要 294epochs 才能跑完一遍数据集。</li></ul></li></ul></li><li>[x] 单机单卡 deepspeed 训练：目前有 torch broadcast 的 bug 待修复。服务器的 nccl ib 通信有问题，设置<code>os.environ[&#39;NCCL_IB_DISABLE&#39;] = &#39;1&#39;</code>将其关闭即可进行<code>deepspeed_stage_2</code>训练 <ul><li>设备：A100 80GiB： <ul><li>bs=64,ctx_len=4096，GRAD_CP=1，显存占用约 34GiB，30min/epoch，需要 294epochs 才能跑完一遍数据集。</li><li>bs=128,ctx_len=4096，GRAD_CP=1，显存占用约 66GiB，30min/epoch，需要 294epochs 才能跑完一遍数据集。</li></ul></li></ul></li><li>[x] 单机多卡 deepspeed 训练：目前有 torch broadcast 的 bug 待修复。服务器的 nccl ib 通信有问题，设置<code>os.environ[&#39;NCCL_IB_DISABLE&#39;] = &#39;1&#39;</code>将其关闭即可进行<code>deepspeed_stage_2</code>训练 <ul><li>设备：8*A100 40GiB： <ul><li>bs=256(32*8),ctx_len=4096，GRAD_CP=1，显存占用约 18GiB，5min/epoch，需要 294epochs 才能跑完一遍数据集，一天足矣。</li></ul></li></ul></li></ul><p>注意到开启梯度检查器后，显存占用大幅下降，而训练速度几乎不变。</p>`,14)]))}const u=n(p,[["render",e]]);export{_ as __pageData,u as default};
